proof fn phi_1_disjoint_mappings_external_body(d: Directory, i: nat, j: nat)
    requires
        d.inv(),
        i < j,
        j < d.entries.len(),
    ensures
        forall|va: nat| d.interp_of_entry(i).contains_key(va) ==> !d.interp_of_entry(j).contains_key(va),
{
    d.lemma_interp_of_entry_disjoint_mappings(i, j);
}

proof fn phi_3_disjoint_symmetric(d: Directory, i: nat, j: nat)
    requires
        d.inv(),
        i < j,
        j < d.entries.len(),
    ensures
        forall|va: nat| d.interp_of_entry(j).contains_key(va) ==> !d.interp_of_entry(i).contains_key(va),
{
    d.lemma_interp_of_entry_disjoint_mappings(i, j);
}
